
import Image from "next/image";
import { useParams } from "next/navigation";
import { useState } from "react";

const colors = [
  { name: "Midnight Blue", value: "#2F4F6F", price: 589 },
  { name: "Deep Purple", value: "#4B2E83", price: 569 },
  { name: "Space Black", value: "#111111", price: 609 },
];

const memoryOptions = ["64GB", "128GB", "256GB", "512GB"];

export default function ProductPage() {
    const  params = useParams()
    console.log(params)
  const [selectedColor, setSelectedColor] = useState(colors[0]);
  const [selectedMemory, setSelectedMemory] = useState("128GB");

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-10 bg-white p-6 rounded-2xl shadow-lg">

        {/* Left - Images */}
        <div>
          <div className="rounded-xl overflow-hidden border">
            <Image
              src="/phone.png"
              alt="product"
              width={500}
              height={500}
              className="object-contain w-full"
            />
          </div>

          <div className="flex gap-3 mt-4">
            {[1, 2, 3].map((i) => (
              <div
                key={i}
                className="w-20 h-20 border rounded-lg flex items-center justify-center cursor-pointer hover:border-[#01A49E]"
              >
                <Image
                  src="/phone.png"
                  alt="thumb"
                  width={60}
                  height={60}
                />
              </div>
            ))}
          </div>
        </div>

        {/* Right - Details */}
        <div className="flex flex-col gap-5">
          <h1 className="text-2xl font-semibold">
            Somseng Galatero X6 Ultra LTE 4G/128GB, Black Smartphone
          </h1>

          <p className="text-2xl font-bold text-[#01A49E]">
            ${selectedColor.price}.00
          </p>

          <ul className="text-sm text-gray-600 space-y-1">
            <li>• Intel LGA 1700 Socket</li>
            <li>• DDR5 Compatible</li>
            <li>• 16+1+2 Phase Digital VRM</li>
          </ul>

          {/* Color Selection */}
          <div>
            <h3 className="font-medium mb-2">Color</h3>
            <div className="flex gap-3">
              {colors.map((color) => (
                <button
                  key={color.name}
                  onClick={() => setSelectedColor(color)}
                  className={`px-4 py-2 border rounded-lg text-sm flex items-center gap-2 ${
                    selectedColor.name === color.name
                      ? "border-[#01A49E] bg-[#01A49E]/10"
                      : "border-gray-300"
                  }`}
                >
                  <span
                    className="w-4 h-4 rounded-full"
                    style={{ backgroundColor: color.value }}
                  ></span>
                  {color.name}
                </button>
              ))}
            </div>
          </div>

          {/* Memory Selection */}
          <div>
            <h3 className="font-medium mb-2">Memory Size</h3>
            <div className="flex gap-3">
              {memoryOptions.map((mem) => (
                <button
                  key={mem}
                  onClick={() => setSelectedMemory(mem)}
                  className={`px-4 py-2 border rounded-lg text-sm ${
                    selectedMemory === mem
                      ? "border-[#01A49E] bg-[#01A49E]/10"
                      : "border-gray-300"
                  }`}
                >
                  {mem}
                </button>
              ))}
            </div>
          </div>

          {/* Promo */}
          <div className="bg-[#01A49E]/10 p-4 rounded-xl text-sm">
            <p>
              Buy <span className="text-[#01A49E] font-semibold">02</span> boxes
              get a Snack Tray
            </p>
            <p>
              Buy <span className="text-[#01A49E] font-semibold">04</span> boxes
              get a free Block Toys
            </p>
          </div>

          {/* Buttons */}
          <div className="flex gap-4 mt-4">
            <button className="flex-1 bg-[#01A49E] text-white py-3 rounded-xl font-medium hover:opacity-90">
              Add to Cart
            </button>
            <button className="flex-1 border border-[#01A49E] text-[#01A49E] py-3 rounded-xl font-medium hover:bg-[#01A49E] hover:text-white">
              Buy Now
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}